def factorial(n):
    if n <= 1:
        return 1
    return n * factorial(n - 1)

print("Factorial 5:", factorial(5))

def fibonacci(n):
    if n <= 1:
        return n
    return fibonacci(n - 1) + fibonacci(n - 2)

print("Fibonacci 7:", fibonacci(7))

def countdown(n):
    if n <= 0:
        print("Liftoff!")
        return
    print(n)
    countdown(n - 1)

countdown(3)
